INSERT INTO `v1_441d5356c1bc9986b1eef84abb7f12d05223a1f4682112e3dfff9fbff6cb1d86` VALUES (2, 2, 1, 3000, "調子が上がって\nきたなっ", 2, "vo_minigame_1013_icon_1_002_001", 1000, "訓練はまだ\nここからですわ", "vo_minigame_1013_icon_2_002_001");
INSERT INTO `v1_441d5356c1bc9986b1eef84abb7f12d05223a1f4682112e3dfff9fbff6cb1d86` VALUES (2, 2, 2, 3000, "ほらほら、\nまだいけるだろ？", 2, "vo_minigame_1013_icon_1_003_001", 5000, "クスクス、悪くない\n流れですわね", "vo_minigame_1013_icon_2_003_001");
INSERT INTO `v1_441d5356c1bc9986b1eef84abb7f12d05223a1f4682112e3dfff9fbff6cb1d86` VALUES (3, 2, 3, 3000, "へへっ、おまえら\nやるじゃねえか！", 2, "vo_minigame_1013_icon_1_004_001", 10000, "すばらしい\n記録ですわ", "vo_minigame_1013_icon_2_004_001");
INSERT INTO `v1_441d5356c1bc9986b1eef84abb7f12d05223a1f4682112e3dfff9fbff6cb1d86` VALUES (3, 2, 4, 3000, "あたしたちはまだ\n止まらねえぜ！", 3, "vo_minigame_1013_icon_1_005_001", 10000, "乗りに乗って\nいますわね", "vo_minigame_1013_icon_2_005_001");
INSERT INTO `v1_441d5356c1bc9986b1eef84abb7f12d05223a1f4682112e3dfff9fbff6cb1d86` VALUES (3, 2, 5, 3000, "見てろよ！\nマコト班の快進撃だ！", 3, "vo_minigame_1013_icon_1_005_002", 10000, "まだまだ行きます\nついてきなさい", "vo_minigame_1013_icon_2_005_002");
INSERT INTO `v1_441d5356c1bc9986b1eef84abb7f12d05223a1f4682112e3dfff9fbff6cb1d86` VALUES (3, 2, 6, 3000, "うおぉぉっ！\n絶好調だぜ！", 3, "vo_minigame_1013_icon_1_005_003", 10000, "エリコ班の\n本領発揮ですわ！", "vo_minigame_1013_icon_2_005_003");
INSERT INTO `v1_441d5356c1bc9986b1eef84abb7f12d05223a1f4682112e3dfff9fbff6cb1d86` VALUES (3, 2, 7, 3000, "どこまで行けるか\n楽しみだなっ！", 4, "vo_minigame_1013_icon_1_006_001", 0, "ここからは\n前人未到の領域です！", "vo_minigame_1013_icon_2_006_001");
INSERT INTO `v1_441d5356c1bc9986b1eef84abb7f12d05223a1f4682112e3dfff9fbff6cb1d86` VALUES (4, 3, 8, 1000, "まだ諦めんなよっ", 5, "vo_minigame_1013_icon_1_007_001", 1, "厄介でしたわ…", "vo_minigame_1013_icon_2_007_001");
INSERT INTO `v1_441d5356c1bc9986b1eef84abb7f12d05223a1f4682112e3dfff9fbff6cb1d86` VALUES (4, 3, 9, 1000, "冷やっとしたぜ…！", 5, "vo_minigame_1013_icon_1_007_002", 1, "油断大敵です", "vo_minigame_1013_icon_2_007_002");
INSERT INTO `v1_441d5356c1bc9986b1eef84abb7f12d05223a1f4682112e3dfff9fbff6cb1d86` VALUES (4, 3, 10, 1000, "弱音を吐くなっ", 5, "vo_minigame_1013_icon_1_007_003", 1, "忌々しいっ…", "vo_minigame_1013_icon_2_007_003");
INSERT INTO `v1_441d5356c1bc9986b1eef84abb7f12d05223a1f4682112e3dfff9fbff6cb1d86` VALUES (3, 4, 11, 1500, "マコト班集合！", 6, "vo_minigame_1013_icon_1_008_001", 99, "大所帯ですわね", "vo_minigame_1013_icon_2_008_001");
INSERT INTO `v1_441d5356c1bc9986b1eef84abb7f12d05223a1f4682112e3dfff9fbff6cb1d86` VALUES (3, 4, 12, 1500, "連携してくぞ！", 6, "vo_minigame_1013_icon_1_008_002", 99, "エリコ班へようこそ", "vo_minigame_1013_icon_2_008_002");
INSERT INTO `v1_441d5356c1bc9986b1eef84abb7f12d05223a1f4682112e3dfff9fbff6cb1d86` VALUES (6, 1, 13, 3000, "みんなに力を！", 8, "vo_minigame_1013_icon_1_020_001", 0, "ナナカちゃんに\nお任せあれ", "vo_minigame_1013_icon_2_020_001");
INSERT INTO `v1_441d5356c1bc9986b1eef84abb7f12d05223a1f4682112e3dfff9fbff6cb1d86` VALUES (7, 1, 14, 3000, "任せてくれたまえ", 9, "vo_minigame_1013_icon_1_022_001", 0, "はっはっは！\n任せろ！", "vo_minigame_1013_icon_2_022_001");
INSERT INTO `v1_441d5356c1bc9986b1eef84abb7f12d05223a1f4682112e3dfff9fbff6cb1d86` VALUES (8, 1, 15, 3000, "ほな、いきまひょか", 10, "vo_minigame_1013_icon_1_023_001", 0, "どんどんいくわよ", "vo_minigame_1013_icon_2_023_001");
